    if (argc < 2) {
        fprintf(stderr, "Usage: deftreeminus [root_process] [OPTION1] [OPTION2] [-processid]\n");
        return 1;
    }

    ProcessNode *head = NULL;

    read_processes(&head);

    unsigned long root_pid = strtoul(argv[1], NULL, 10);
