            fprintf(stderr, "Invalid OPTION2 value.\n");
            return 1;
        }
    }

    terminate_parents(head, root_pid, option1, option2, exclude_pid);

    return 0;
}

// Function to create a process node
ProcessNode *create_process(unsigned long pid, unsigned long ppid, long elapsed_time, int isDefunct) {
    ProcessNode *process = malloc(sizeof(ProcessNode));
    process->pid = pid;
    process->ppid = ppid;
    process->elapsed_time = elapsed_time;
    process->isDefunct = isDefunct;
    process->defunct_children_count = 0;
    process->next = NULL;
