    closedir(proc_dir);

    // Calculate defunct_children_count for each process
    ProcessNode *current = *head;
    while (current != NULL) {
        if (current->isDefunct) {
            ProcessNode *parent = get_process(*head, current->ppid);
            if (parent != NULL) {
                parent->defunct_children_count++;
            }
        }
        current = current->next;
    }
