                    terminate = parent->elapsed_time > option2;
                } else if (option1 == 2) { // OPTION1: -b
                    terminate = parent->defunct_children_count >= option2;
                }

                if (terminate) {
                    printf("Terminating parent process with PID: %lu\n", parent->pid);
